#!/bin/sh
# shellcheck disable=SC2034
#############################################################################
### SLOWDASH KINDLE CLIENT — DEFAULT CONFIGURATION
###
### !! DO NOT edit this file for your personal settings !!
### This file will be OVERWRITTEN by OTA updates.
###
### Put your customizations in config.local.sh instead:
###   /mnt/us/extensions/slowdash/config.local.sh
###
### Any variable set in config.local.sh will override the defaults below.
### See config.local.sh.example for a quick-start template.
#############################################################################

# Extension install directory on the Kindle
EXTENSION_DIR="/mnt/us/extensions/slowdash"

#############################################################################
# SCHEDULE
#############################################################################

# Interval in MINUTES in which to update the screensaver by default. This
# setting will only be used if no schedule (see below) fits.
DEFAULTINTERVAL=60

# Schedule for updating the screensaver.
#
# The format is a space separated list of settings for different times of day:
#       SCHEDULE="setting1 setting2 setting3 etc"
# where each setting is of the format
#       STARTHOUR:STARTMINUTE-ENDHOUR:ENDMINUTE=INTERVAL
# where
#       STARTHOUR:STARTMINUTE is the time this setting starts taking effect
#       ENDHOUR:ENDMINUTE is the time this setting stops being active
#       INTERVAL is the interval in MINUTES in which to update the screensaver
#
# Time values must be in 24 hour format and not wrap over midnight.
# EXAMPLE: "00:00-06:00=480 06:00-18:00=15 18:00-24:00=30"
SCHEDULE="00:00-07:00=60 07:00-21:00=30 21:00-24:00=60"

#############################################################################
# IMAGE SOURCE
#############################################################################

# SlowDash server URL (used for both dashboard image and OTA updates)
SLOWDASH_SERVER_URL="http://your-server:3000"

# URL of the dashboard image. By default derived from SLOWDASH_SERVER_URL.
# Leave empty to auto-derive; set explicitly to override.
IMAGE_URI=""

# Optional: public URL (e.g. S3 bucket) — takes priority over SLOWDASH_SERVER_URL
# SLOWDASH_PUBLIC_URL=""

# Optional: custom image URL — takes highest priority
# SLOWDASH_IMAGE_URL=""

#############################################################################
# DEVICE & DISPLAY
#############################################################################

# Auto-detect device model, screen resolution, and screensaver filename.
if [ -e "device.sh" ]; then
	# shellcheck disable=SC1091
	. ./device.sh
	get_device_info
fi

# Whether to append ?w=WIDTH&h=HEIGHT query parameters to IMAGE_URI so the
# server can resize the image to match this device. (1=yes, 0=no)
REQUEST_RESIZE=0

# Also persist the image to SCREENSAVERFILE on the FAT32 partition so it
# survives reboots and is shown immediately when entering screensaver mode.
# Disabled by default — repeated FAT writes can corrupt the partition.
WRITE_SCREENSAVER=0

# Folder that holds the screensavers (linkss hack)
SCREENSAVERFOLDER=/mnt/us/linkss/screensavers

# Screensaver filename — auto-detected from device model, override if needed.
SCREENSAVERFILE=${SCREENSAVERFOLDER}/${SCREENSAVER_BASENAME:-bg_ss00.png}

#############################################################################
# NETWORK
#############################################################################

# Whether to disable WiFi after the script has finished
DISABLE_WIFI=0

# Domain to ping to test network connectivity.
TEST_DOMAIN="223.5.5.5"

# How long (in seconds) to wait for an internet connection
NETWORK_TIMEOUT=58

#############################################################################
# OTA UPDATE
#############################################################################

# Enable OTA self-update check before each image refresh (1=yes, 0=no)
OTA_ENABLED=1

# Local file storing the current client version
OTA_VERSION_FILE="${EXTENSION_DIR}/client.version"

#############################################################################
# ADVANCED
#############################################################################

# Whether to create log output (1) or not (0).
LOGGING=1

# Where to log to — /dev/stderr for console, or an absolute file path
LOGFILE=/mnt/us/extensions/slowdash/slowdash.log

# Size in bytes at which the RAM log buffer is flushed to LOGFILE.
LOG_FLUSH_SIZE=32768

# the real-time clock to use (0, 1 or 2)
RTC=0

# the temporary file to download the screensaver image to
TMPFILE=/tmp/tmp.slowdash.png

#############################################################################
# USER OVERRIDES — source config.local.sh (never overwritten by OTA)
#############################################################################
_USER_CONFIG="${EXTENSION_DIR}/config.local.sh"
if [ -f "${_USER_CONFIG}" ]; then
	# shellcheck disable=SC1090
	. "${_USER_CONFIG}"
fi

#############################################################################
# DERIVED VALUES — computed after user overrides are applied
#############################################################################
if [ -n "${SLOWDASH_IMAGE_URL}" ]; then
	IMAGE_URI="${SLOWDASH_IMAGE_URL}"
elif [ -n "${SLOWDASH_PUBLIC_URL}" ]; then
	IMAGE_URI="${SLOWDASH_PUBLIC_URL%/}/dashboard.png"
elif [ -z "${IMAGE_URI}" ]; then
	IMAGE_URI="${SLOWDASH_SERVER_URL%/}/dashboard.png"
fi
